import scala.xml.XML
import scala.xml.Node
import scala.util.Try

trait ConfigurationService {
  def parseConfiguration(xmlString: String): Try[Node]
  def extractSettings(config: Node): Map[String, String]
}

class XmlConfigurationService extends ConfigurationService {
  override def parseConfiguration(xmlString: String): Try[Node] = {
    Try(XML.loadString(xmlString))
  }
  
  override def extractSettings(config: Node): Map[String, String] = {
    val settings = scala.collection.mutable.Map[String, String]()
    
    def extract(node: Node): Unit = {
      node.child.foreach { child =>
        child match {
          case elem: scala.xml.Elem if elem.label == "setting" =>
            val name = (elem \ "@name").text
            val value = (elem \ "@value").text
            if (name.nonEmpty && value.nonEmpty) {
              settings(name) = value
            }
          case _ => extract(child)
        }
      }
    }
    
    extract(config)
    settings.toMap
  }
}

object ConfigurationParser {
  def parseAndExtract(xmlString: String): Try[Map[String, String]] = {
    val service = new XmlConfigurationService
    for {
      config <- service.parseConfiguration(xmlString)
      settings <- Try(service.extractSettings(config))
    } yield settings
  }
}